{"path":"arm_m0_min/rtl/arm_m0_min_if.sv","content":"module arm_m0_min_if #(
    parameter integer XLEN = 32,
    parameter integer RESET_PC = 0
) (
    input  logic             clk,
    input  logic             rst,
    input  logic             fault_halt,
    input  logic             hold_pc,
    input  logic             branch_taken,
    input  logic [XLEN-1:0]  branch_target,
    output logic [XLEN-1:0]  pc_out,
    output logic             if_valid,
    output logic [31:0]      if_instr,
    output logic [XLEN-1:0]  i_haddr,
    output logic [1:0]       i_htrans,
    output logic             i_hwrite,
    output logic [2:0]       i_hsize,
    output logic [2:0]       i_hburst,
    output logic [3:0]       i_hprot,
    output logic             i_hmastlock,
    input  logic             i_hready,
    input  logic [31:0]      i_hrdata,
    input  logic             i_hresp
);

    localparam [1:0] HTRANS_IDLE   = 2'b00,
                     HTRANS_NONSEQ = 2'b10;

    logic [XLEN-1:0] pc_reg;

    always @(posedge clk) begin
        if (rst) begin
            pc_reg   <= RESET_PC[XLEN-1:0];
            if_instr <= 32'h00000000;
            if_valid <= 1'b0;
        end else if (!fault_halt) begin
            if (i_hready) begin
                if_instr <= i_hrdata;
                if_valid <= 1'b1;
                if (branch_taken) begin
                    pc_reg <= branch_target;
                end else if (!hold_pc) begin
                    pc_reg <= pc_reg + 32'd2;
                end
            end
        end
    end

    assign pc_out      = pc_reg;
    assign i_haddr     = pc_reg;
    assign i_htrans    = (fault_halt) ? HTRANS_IDLE : HTRANS_NONSEQ;
    assign i_hwrite    = 1'b0;
    assign i_hsize     = 3'b001;
    assign i_hburst    = 3'b000;
    assign i_hprot     = 4'b0011;
    assign i_hmastlock = 1'b0;

endmodule
"}

{"path":"arm_m0_min/rtl/arm_m0_min_alu.sv","content":"module arm_m0_min_alu #(
    parameter integer XLEN = 32
) (
    input  logic [3:0]       alu_op,
    input  logic [XLEN-1:0]  op_a,
    input  logic [XLEN-1:0]  op_b,
    output logic [XLEN-1:0]  alu_res,
    output logic             cmp_eq,
    output logic             cmp_neg
);

    localparam [3:0] ALU_ADD = 4'd0,
                     ALU_SUB = 4'd1,
                     ALU_AND = 4'd2,
                     ALU_ORR = 4'd3,
                     ALU_EOR = 4'd4,
                     ALU_MOV = 4'd5,
                     ALU_LSL = 4'd6,
                     ALU_LSR = 4'd7,
                     ALU_ASR = 4'd8;

    logic [4:0] shamt;
    assign shamt = op_b[4:0];

    always @(*) begin
        alu_res = {XLEN{1'b0}};
        case (alu_op)
            ALU_ADD: alu_res = op_a + op_b;
            ALU_SUB: alu_res = op_a - op_b;
            ALU_AND: alu_res = op_a & op_b;
            ALU_ORR: alu_res = op_a | op_b;
            ALU_EOR: alu_res = op_a ^ op_b;
            ALU_MOV: alu_res = op_b;
            ALU_LSL: alu_res = op_a << shamt;
            ALU_LSR: alu_res = op_a >> shamt;
            ALU_ASR: alu_res = $signed(op_a) >>> shamt;
            default: alu_res = {XLEN{1'b0}};
        endcase
    end

    assign cmp_eq  = (op_a == op_b);
    assign cmp_neg = (op_a < op_b);

endmodule
"}

{"path":"arm_m0_min/rtl/arm_m0_min_branch.sv","content":"module arm_m0_min_branch #(
    parameter integer XLEN = 32
) (
    input  logic [XLEN-1:0] pc_in,
    input  logic [XLEN-1:0] imm_ext,
    input  logic            is_b,
    input  logic            is_beq,
    input  logic            is_bne,
    input  logic            z_flag,
    output logic            branch_taken,
    output logic [XLEN-1:0] branch_target
);

    always @(*) begin
        branch_taken  = 1'b0;
        branch_target = pc_in + imm_ext;
        if (is_b) begin
            branch_taken = 1'b1;
        end else if (is_beq) begin
            if (z_flag) branch_taken = 1'b1;
        end else if (is_bne) begin
            if (!z_flag) branch_taken = 1'b1;
        end
    end

endmodule
"}

{"path":"arm_m0_min/rtl/arm_m0_min_mem_if.sv","content":"module arm_m0_min_mem_if #(
    parameter integer XLEN = 32
) (
    input  logic             is_ldr,
    input  logic             is_str,
    input  logic [XLEN-1:0]  base_addr,
    input  logic [XLEN-1:0]  imm_ext,
    input  logic [XLEN-1:0]  store_data,
    output logic [XLEN-1:0]  d_haddr,
    output logic [1:0]       d_htrans,
    output logic             d_hwrite,
    output logic [2:0]       d_hsize,
    output logic [2:0]       d_hburst,
    output logic [3:0]       d_hprot,
    output logic             d_hmastlock,
    output logic [XLEN-1:0]  d_hwdata
);

    localparam [1:0] HTRANS_IDLE   = 2'b00,
                     HTRANS_NONSEQ = 2'b10;

    logic mem_req;
    assign mem_req = is_ldr | is_str;

    assign d_haddr     = base_addr + imm_ext;
    assign d_htrans    = mem_req ? HTRANS_NONSEQ : HTRANS_IDLE;
    assign d_hwrite    = is_str;
    assign d_hsize     = 3'b010;
    assign d_hburst    = 3'b000;
    assign d_hprot     = 4'b0011;
    assign d_hmastlock = 1'b0;
    assign d_hwdata    = is_str ? store_data : {XLEN{1'b0}};

endmodule
"}

{"path":"arm_m0_min/rtl/arm_m0_min_rf.sv","content":"module arm_m0_min_rf #(
    parameter integer XLEN = 32
) (
    input  logic             clk,
    input  logic             rst,
    input  logic [3:0]       rs1_addr,
    input  logic [3:0]       rs2_addr,
    output logic [XLEN-1:0]  rs1_data,
    output logic [XLEN-1:0]  rs2_data,
    input  logic             we,
    input  logic [3:0]       rd_addr,
    input  logic [XLEN-1:0]  rd_data
);

    logic [XLEN-1:0] rf0;
    logic [XLEN-1:0] rf1;
    logic [XLEN-1:0] rf2;
    logic [XLEN-1:0] rf3;
    logic [XLEN-1:0] rf4;
    logic [XLEN-1:0] rf5;
    logic [XLEN-1:0] rf6;
    logic [XLEN-1:0] rf7;
    logic [XLEN-1:0] rf8;
