    logic [XLEN-1:0] rf12;
    logic [XLEN-1:0] rf13;
    logic [XLEN-1:0] rf14;
    logic [XLEN-1:0] rf15;

    always @(posedge clk) begin
        if (rst) begin
            rf0  <= {XLEN{1'b0}}; rf1  <= {XLEN{1'b0}}; rf2  <= {XLEN{1'b0}}; rf3  <= {XLEN{1'b0}};
            rf4  <= {XLEN{1'b0}}; rf5  <= {XLEN{1'b0}}; rf6  <= {XLEN{1'b0}}; rf7  <= {XLEN{1'b0}};
            rf8  <= {XLEN{1'b0}}; rf9  <= {XLEN{1'b0}}; rf10 <= {XLEN{1'b0}}; rf11 <= {XLEN{1'b0}};
            rf12 <= {XLEN{1'b0}}; rf13 <= {XLEN{1'b0}}; rf14 <= {XLEN{1'b0}}; rf15 <= {XLEN{1'b0}};
        end else if (we) begin
            case (rd_addr)
                4'd0:  rf0  <= rd_data;
                4'd1:  rf1  <= rd_data;
                4'd2:  rf2  <= rd_data;
                4'd3:  rf3  <= rd_data;
                4'd4:  rf4  <= rd_data;
                4'd5:  rf5  <= rd_data;
                4'd6:  rf6  <= rd_data;
                4'd7:  rf7  <= rd_data;
                4'd8:  rf8  <= rd_data;
                4'd9:  rf9  <= rd_data;
                4'd10: rf10 <= rd_data;
                4'd11: rf11 <= rd_data;
                4'd12: rf12 <= rd_data;
                4'd13: rf13 <= rd_data;
                4'd14: rf14 <= rd_data;
                4'd15: rf15 <= rd_data;
                default: ;
            endcase
        end
    end

    always @(*) begin
        case (rs1_addr)
            4'd0: rs1_data = rf0;   4'd1: rs1_data = rf1;   4'd2: rs1_data = rf2;   4'd3: rs1_data = rf3;
            4'd4: rs1_data = rf4;   4'd5: rs1_data = rf5;   4'd6: rs1_data = rf6;   4'd7: rs1_data = rf7;
            4'd8: rs1_data = rf8;   4'd9: rs1_data = rf9;   4'd10: rs1_data = rf10; 4'd11: rs1_data = rf11;
            4'd12: rs1_data = rf12; 4'd13: rs1_data = rf13; 4'd14: rs1_data = rf14; 4'd15: rs1_data = rf15;
            default: rs1_data = {XLEN{1'b0}};
        endcase
    end

    always @(*) begin
        case (rs2_addr)
            4'd0: rs2_data = rf0;   4'd1: rs2_data = rf1;   4'd2: rs2_data = rf2;   4'd3: rs2_data = rf3;
            4'd4: rs2_data = rf4;   4'd5: rs2_data = rf5;   4'd6: rs2_data = rf6;   4'd7: rs2_data = rf7;
            4'd8: rs2_data = rf8;   4'd9: rs2_data = rf9;   4'd10: rs2_data = rf10; 4'd11: rs2_data = rf11;
            4'd12: rs2_data = rf12; 4'd13: rs2_data = rf13; 4'd14: rs2_data = rf14; 4'd15: rs2_data = rf15;
            default: rs2_data = {XLEN{1'b0}};
        endcase
    end

endmodule
"}

{"path":"arm_m0_min/rtl/arm_m0_min_id.sv","content":"module arm_m0_min_id #(
    parameter integer XLEN = 32
) (
    input  logic             clk,
    input  logic             rst,
    input  logic             fault_halt,
    input  logic             if_valid,
    input  logic [31:0]      if_instr,
    input  logic [XLEN-1:0]  pc_in,
    input  logic [3:0]       nzcv,
    output logic             id_valid,
    output logic [3:0]       rs1_addr,
    output logic [3:0]       rs2_addr,
    output logic [3:0]       rd_addr,
    output logic [XLEN-1:0]  imm_ext,
    output logic [3:0]       alu_op,
    output logic             is_cmp,
    output logic             is_ldr,
    output logic             is_str,
    output logic             is_b,
    output logic             is_beq,
    output logic             is_bne,
    output logic             is_undef
);

    localparam [3:0] OP_ADD = 4'h0,
                     OP_SUB = 4'h1,
                     OP_AND = 4'h2,
                     OP_ORR = 4'h3,
                     OP_EOR = 4'h4,
                     OP_MOV = 4'h5,
                     OP_CMP = 4'h6,
                     OP_LDR = 4'h7,
                     OP_STR = 4'h8,
                     OP_B   = 4'h9,
                     OP_BEQ = 4'hA,
                     OP_BNE = 4'hB,
                     OP_LSL = 4'hC,
                     OP_LSR = 4'hD,
                     OP_ASR = 4'hE;

    localparam [3:0] ALU_ADD = 4'd0,
                     ALU_SUB = 4'd1,
                     ALU_AND = 4'd2,
                     ALU_ORR = 4'd3,
                     ALU_EOR = 4'd4,
                     ALU_MOV = 4'd5,
                     ALU_LSL = 4'd6,
                     ALU_LSR = 4'd7,
                     ALU_ASR = 4'd8;

    logic [15:0] instr16;
    assign instr16 = if_instr[15:0];

    always @(*) begin
        id_valid  = if_valid & !fault_halt;
        rs1_addr  = instr16[11:8];
        rs2_addr  = instr16[7:4];
        rd_addr   = instr16[3:0];
        imm_ext   = {{24{instr16[7]}}, instr16[7:0]};
        alu_op    = ALU_ADD;
        is_cmp    = 1'b0;
        is_ldr    = 1'b0;
        is_str    = 1'b0;
        is_b      = 1'b0;
        is_beq    = 1'b0;
        is_bne    = 1'b0;
        is_undef  = 1'b0;

        case (instr16[15:12])
            OP_ADD: begin
                alu_op = ALU_ADD;
            end
            OP_SUB: begin
                alu_op = ALU_SUB;
            end
            OP_AND: begin
                alu_op = ALU_AND;
            end
            OP_ORR: begin
                alu_op = ALU_ORR;
            end
            OP_EOR: begin
                alu_op = ALU_EOR;
            end
            OP_MOV: begin
                alu_op = ALU_MOV;
            end
            OP_CMP: begin
                alu_op = ALU_SUB;
                is_cmp = 1'b1;
            end
            OP_LDR: begin
                is_ldr = 1'b1;
            end
            OP_STR: begin
                is_str = 1'b1;
            end
            OP_B: begin
                is_b = 1'b1;
            end
            OP_BEQ: begin
                if (nzcv[2]) is_beq = 1'b1;
            end
            OP_BNE: begin
                if (!nzcv[2]) is_bne = 1'b1;
            end
            OP_LSL: begin
                alu_op = ALU_LSL;
            end
            OP_LSR: begin
                alu_op = ALU_LSR;
            end
            OP_ASR: begin
                alu_op = ALU_ASR;
            end
            default: begin
                is_undef = 1'b1;
            end
        endcase
    end

endmodule
"}

{"path":"arm_m0_min/rtl/arm_m0_min_ex.sv","content":"module arm_m0_min_ex #(
    parameter integer XLEN = 32,
    parameter integer ENABLE_FAULT_HALT = 1
) (
    input  logic             clk,
    input  logic             rst,
    input  logic             id_valid,
    input  logic [XLEN-1:0]  pc_in,
    input  logic [XLEN-1:0]  rs1_data,
    input  logic [XLEN-1:0]  rs2_data,
    input  logic [3:0]       rd_addr,
    input  logic [XLEN-1:0]  imm_ext,
    input  logic [3:0]       alu_op,
    input  logic             is_cmp,
    input  logic             is_ldr,
    input  logic             is_str,
    input  logic             is_b,
    input  logic             is_beq,
    input  logic             is_bne,
    input  logic             is_undef,
    input  logic             i_hready,
    input  logic             i_hresp,
    input  logic             d_hready,
    input  logic [XLEN-1:0]  d_hrdata,
    input  logic             d_hresp,
    output logic             rf_we,
    output logic [3:0]       rf_waddr,
    output logic [XLEN-1:0]  rf_wdata,
    output logic [3:0]       nzcv,
    output logic             fault_halt,
    output logic             hold_pc,
    output logic             branch_taken,
    output logic [XLEN-1:0]  branch_target,
    output logic [XLEN-1:0]  d_haddr,
    output logic [1:0]       d_htrans,
    output logic             d_hwrite,
    output logic [2:0]       d_hsize,
    output logic [2:0]       d_hburst,
    output logic [3:0]       d_hprot,
    output logic             d_hmastlock,
    output logic [XLEN-1:0]  d_hwdata
);
    localparam [2:0] ST_RESET = 3'd0,
                     ST_RUN = 3'd1,
                     ST_STALL_IF = 3'd2,
                     ST_STALL_MEM = 3'd3,
                     ST_FAULT_HALT = 3'd4;

    logic [2:0] state, next_state;
    logic [XLEN-1:0] alu_res;
    logic cmp_eq, cmp_neg;
    logic branch_taken_w;
    logic [XLEN-1:0] branch_target_w;

    arm_m0_min_alu #(.XLEN(XLEN)) u_alu (
        .alu_op(alu_op), .op_a(rs1_data), .op_b(rs2_data), .alu_res(alu_res), .cmp_eq(cmp_eq), .cmp_neg(cmp_neg)
    );

    arm_m0_min_branch #(.XLEN(XLEN)) u_branch (
        .pc_in(pc_in), .imm_ext(imm_ext), .is_b(is_b), .is_beq(is_beq), .is_bne(is_bne), .z_flag(nzcv[2]),
        .branch_taken(branch_taken_w), .branch_target(branch_target_w)
    );

    arm_m0_min_mem_if #(.XLEN(XLEN)) u_memif (
        .is_ldr(is_ldr), .is_str(is_str), .base_addr(rs1_data), .imm_ext(imm_ext), .store_data(rs2_data),
        .d_haddr(d_haddr), .d_htrans(d_htrans), .d_hwrite(d_hwrite), .d_hsize(d_hsize), .d_hburst(d_hburst),
        .d_hprot(d_hprot), .d_hmastlock(d_hmastlock), .d_hwdata(d_hwdata)
    );

    always @(posedge clk) begin
        if (rst) begin
            state <= ST_RESET;
            fault_halt <= 1'b0;
            nzcv <= 4'b0000;
        end else begin
            state <= next_state;
            if (ENABLE_FAULT_HALT == 1) begin
                if ((i_hready & i_hresp) || ((is_ldr || is_str) && d_hready && d_hresp) || (id_valid && is_undef))
                    fault_halt <= 1'b1;
            end
            if (is_cmp && id_valid && !fault_halt) begin
                nzcv[3] <= alu_res[XLEN-1];
                nzcv[2] <= cmp_eq;
                nzcv[1] <= 1'b0;
                nzcv[0] <= cmp_neg;
            end
        end
    end

    always @(*) begin
        next_state = state;
        case (state)
            ST_RESET: next_state = ST_RUN;
            ST_RUN: begin
                if (fault_halt) next_state = ST_FAULT_HALT;
                else if (!i_hready) next_state = ST_STALL_IF;
                else if ((is_ldr || is_str) && !d_hready) next_state = ST_STALL_MEM;
            end
            ST_STALL_IF: begin
                if (fault_halt) next_state = ST_FAULT_HALT;
                else if (i_hready) next_state = ST_RUN;
            end
            ST_STALL_MEM: begin
                if (fault_halt) next_state = ST_FAULT_HALT;
                else if (d_hready && !d_hresp) next_state = ST_RUN;
            end
            ST_FAULT_HALT: next_state = ST_FAULT_HALT;
            default: next_state = ST_RESET;
        endcase
    end

    always @(*) begin
        rf_we = 1'b0;
        rf_waddr = rd_addr;
        rf_wdata = alu_res;
        hold_pc = 1'b0;
        branch_taken = 1'b0;
        branch_target = branch_target_w;

        if (state == ST_STALL_IF || state == ST_STALL_MEM || fault_halt)
            hold_pc = 1'b1;

        if (id_valid && !fault_halt) begin
            if (is_ldr) begin
                if (d_hready) begin
                    rf_we = 1'b1;
                    rf_wdata = d_hrdata;
                end
            end else if (is_str) begin
                rf_we = 1'b0;
            end else if (is_cmp) begin
                rf_we = 1'b0;
            end else if (is_b || is_beq || is_bne) begin
                branch_taken = branch_taken_w;
                rf_we = 1'b0;
            end else if (!is_undef) begin
                rf_we = 1'b1;
            end
        end
    end

endmodule
"}

{"path":"arm_m0_min/rtl/arm_m0_min.sv","content":"module arm_m0_min #(
    parameter integer XLEN = 32,
    parameter integer RESET_PC = 0,
    parameter integer ENABLE_FAULT_HALT = 1
) (
    input  logic             clk,
    input  logic             rst,
    output logic [31:0]      i_haddr,
    output logic [1:0]       i_htrans,
    output logic             i_hwrite,
    output logic [2:0]       i_hsize,
    output logic [2:0]       i_hburst,
    output logic [3:0]       i_hprot,
    output logic             i_hmastlock,
    input  logic             i_hready,
    input  logic [31:0]      i_hrdata,
    input  logic             i_hresp,
    output logic [31:0]      d_haddr,
    output logic [1:0]       d_htrans,
    output logic             d_hwrite,
    output logic [2:0]       d_hsize,
    output logic [2:0]       d_hburst,
    output logic [3:0]       d_hprot,
